func:
msg._areas = msg.areas || [];
msg._prompt = msg.prompt || 'something funny';
msg._announcement = msg.announcement || msg._prompt;

msg.url = 'http://hal-9005.lan:11434/api/chat';
msg.headers = { 'Content-Type': 'application/json' };

const systemPrompt = `You are Silly Connolly, a comedy chatbot inspired by the legendary Scottish comedian Billy Connolly — the Big Yin himself.

Your personality:
- You are a working-class Glaswegian storyteller with a wicked, irreverent sense of humour
- You tell jokes, stories, and observations rooted in Scottish culture, Glasgow life, and the absurdity of everyday human existence
- You use Scottish words and phrases naturally: "wee", "aye", "nae bother", "braw", "dinnae", "heid", "bampot", "eejit", "blether", "haver", "numpty", "wheesht", "ya beauty", "pure dead brilliant"
- You draw on Scottish cultural touchstones: Glasgow patter, shipyard humour, Scottish drinking culture, Irn-Bru, haggis, ceilidhs, the weather, fitba
- You find the hilarious in the mundane — filtered through a distinctly Scottish, working-class lens
- Profanity flows naturally as authentic working-class Scottish speech, not for shock value

QUIPS AND TTS MODE:
- ONE or TWO sentences max. That's it.
- Output ONLY the quip text. Nothing else.
- No quotation marks. No preamble. No follow-up. No stage directions.
- No asterisks, no parentheses, no formatting of any kind.
- No offering alternatives or options.
- Just the raw spoken words, ready for text-to-speech.

IMPORTANT: NEVER write in phonetic spelling or try to represent a Scottish accent. Use proper Scottish words and phrases in standard spelling.`;

msg.payload = {
    model: 'gemma4:latest',
    messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: 'Give me a quip about the ' + msg._prompt }
    ],
    stream: false,
    options: { temperature: 0.9, top_p: 0.9 }
};
return msg;

if (!msg.payload || !msg.payload.message) {
    node.error('Ollama error: ' + JSON.stringify(msg.payload).substring(0, 300), msg);
    return null;
}
const quip = msg.payload.message.content;
node.status({fill:'green', shape:'dot', text: quip.substring(0, 40)});
msg.quip = quip;
return msg;

msg.url = 'https://api.fish.audio/v1/tts';
msg.headers = {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer 9135dc4898034acfa4b2c84d238def2c',
    'model': 's2-pro'
};
msg.payload = {
    text: msg.quip,
    reference_id: '0d34211209014116ac7f82d4c4df035f',
    format: 'mp3',
    model: 's2-pro',
    temperature: 0.7,
    top_p: 0.7
};
return msg;

if (msg.statusCode !== 200 || !msg.payload || msg.payload.length < 1000) {
    node.error('TTS failed: HTTP ' + msg.statusCode + ', size=' + (msg.payload ? msg.payload.length : 0), msg);
    return null;
}
return msg;

msg.payload = Buffer.concat([msg._ttsAudio, msg.payload]);
delete msg._ttsAudio;
node.status({fill:'green', shape:'dot', text: msg.payload.length + ' bytes total'});
return msg;

const rawAreas = msg._areas || [];
const mediaUrl = 'http://homeassistant.lan:8123/local/tts/silly-connolly-quip.mp3';

// Filter out x-prefixed areas (disabled for testing)
const areas = rawAreas.filter(a => !a.startsWith('x'));

// Area name → entity mapping
const areaMap = {
    'living room': ['media_player.zigbee2mqtt'],
    'family room': ['media_player.family_room_pi'],
    'office': ['media_player.google_hub_office', 'media_player.octopi5']
};

let players = [];
if (areas.length === 0 && rawAreas.length === 0) {
    // No areas at all - announce on all
    for (const p of Object.values(areaMap)) players.push(...p);
} else {
    for (const area of areas) {
        const mapped = areaMap[area.toLowerCase()];
        if (mapped) {
            players.push(...mapped);
        } else {
            node.error('Unknown area: ' + area, msg);
            return null;
        }
    }
}

players = [...new Set(players)];

if (players.length === 0) {
    node.error('No media players found for: ' + areas.join(', '), msg);
    node.status({fill:'red', shape:'dot', text: 'No players'});
    return null;
}

const label = (areas.length === 0 && rawAreas.length === 0) ? 'ALL' : areas.join(', ');
node.status({fill:'green', shape:'dot', text: players.length + ' speakers in ' + label});
node.warn('Playing on: ' + players.join(', '));

const messages = players.map(entityId => ({
    payload: {
        data: {
            media_content_id: mediaUrl,
            media_content_type: 'audio/mp3',
            entity_id: entityId
        }
    }
}));

return [messages];

// Determine which step failed
var source = (msg.error && msg.error.source) || {};
var failedNode = source.name || source.id || 'unknown';
var errorMsg = (msg.error && msg.error.message) || 'unknown error';
var preamble = '';
if (failedNode.indexOf('Ollama') >= 0 || failedNode.indexOf('Quip') >= 0) {
    preamble = 'Quip generation failed.';
} else if (failedNode.indexOf('TTS') >= 0 || failedNode.indexOf('Fish') >= 0 || failedNode.indexOf('Check TTS') >= 0) {
    preamble = 'Voice synthesis failed.';
} else if (failedNode.indexOf('Save') >= 0 || failedNode.indexOf('Silence') >= 0 || failedNode.indexOf('Concat') >= 0) {
    preamble = 'Audio save failed.';
} else if (failedNode.indexOf('Play') >= 0 || failedNode.indexOf('Resolve') >= 0) {
    preamble = 'Speaker playback failed.';
} else {
    preamble = 'Something went wrong.';
}

var backup = msg._announcement || msg.announcement || msg._prompt || 'something funny';
var message = preamble + ' ' + backup;

// Translate areas to snake_case for Kearney
var rawAreas = msg._areas || msg.areas || [];
var areaMap = {
    'living room': 'living_room',
    'family room': 'family_room',
    'office': 'office'
};
var kearneyAreas = [];
if (rawAreas.length === 0) {
    kearneyAreas = ['living_room', 'family_room', 'guest_bedroom', 'office'];
} else {
    for (var i = 0; i < rawAreas.length; i++) {
        var a = rawAreas[i];
        if (a.startsWith('x')) continue;
        var mapped = areaMap[a.toLowerCase()];
        if (mapped) kearneyAreas.push(mapped);
    }
    if (kearneyAreas.length === 0) {
        kearneyAreas = ['living_room', 'family_room', 'guest_bedroom', 'office'];
    }
}

msg.payload = {
    level: 'announcement',
    areas: kearneyAreas,
    message: message
};

var detail = 'Silly Connolly fallback — node: ' + failedNode + ' | error: ' + errorMsg;
node.status({fill:'yellow', shape:'dot', text: 'Fallback: ' + failedNode});
node.warn(detail);
return msg;
